function minRemoveToMakeValid(s) {
  const out = s.split("");
  const stack = [];

  for (let i = 0; i < out.length; i++) {
    const ch = out[i];
    if (ch === "(") {
      stack.push(i);
    } else if (ch === ")") {
      if (stack.length) stack.pop();
      else out[i] = "";
    }
  }

  while (stack.length) {
    const idx = stack.pop();
    out[idx] = "";
  }

  return out.join("");
}

string MinRemoveToMakeValid(string s)
{
    var chars = s.ToCharArray();
    var stack = new Stack<int>();

    for (int i = 0; i < chars.Length; i++)
    {
        if (chars[i] == '(') stack.Push(i);
        else if (chars[i] == ')')
        {
            if (stack.Count > 0) stack.Pop();
            else chars[i] = '\0';
        }
    }

    while (stack.Count > 0) chars[stack.Pop()] = '\0';

    var sb = new System.Text.StringBuilder();
    foreach (char ch in chars) if (ch != '\0') sb.Append(ch);
    return sb.ToString();
}

def minRemoveToMakeValid(s):
    chars = list(s)
    stack = []

    for i, ch in enumerate(chars):
        if ch == '(':
            stack.append(i)
        elif ch == ')':
            if stack:
                stack.pop()
            else:
                chars[i] = ''

    for i in stack:
        chars[i] = ''

    return ''.join(chars)

